sys_script_client.script:
function onChange(control, oldValue, newValue, isLoading, isTemplate) {

    /**
	GEM/Duypd - 14.05.2026:
	TAM/Sprint 3/Story TAM_42.
	Only display field u_hard_soft when block is bidding.
	Clear value when hidden field.
	Store value block bidding in variable VALUE_DISPLAY.
    */

    var VALUE_DISPLAY = "bidding";
    if (newValue != VALUE_DISPLAY) {
        g_form.setMandatory("u_hard_soft", false);
		g_form.clearValue("u_hard_soft");
        g_form.setDisplay("u_hard_soft", false);
    } else {
        g_form.setDisplay("u_hard_soft", true);
        g_form.setMandatory("u_hard_soft", true);
    }

}
